```javascript
import React from 'react';
import { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('/api/data');
        const json = await response.json();
        setData(json);
      } catch (error) {
        console.error('Error:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  return (
    <div className="App">
      <h1>My Application</h1>
      {loading ? (
        <p>Loading...</p>
      ) : (
        <div>{data}</div>
      )}
    </div>
  );
}
```

---

## What This Component Does

| Part | Explanation |
|------|-------------|
| `useState` hooks | Manages `data` (from API) and `loading` state |
| `useEffect` | Runs once on mount to fetch data from the API |
| `fetch('/api/data')` | Calls a backend API endpoint for data |
| Conditional rendering | Shows "Loading..." until data arrives, then displays it |

---

